import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{a as i,i as a,n as o,r as s,t as c}from"./chunks/javadoc.By8MmAW1.js";const l=JSON.parse(`{"title":"Generating Sources in IntelliJ IDEA","description":"A guide to generating Minecraft sources in IntelliJ IDEA.","frontmatter":{"title":"Generating Sources in IntelliJ IDEA","description":"A guide to generating Minecraft sources in IntelliJ IDEA.","authors":["dicedpixels"],"prev":{"text":"Launching the Game in IntelliJ IDEA","link":"./launching-the-game"},"next":{"text":"Tips and Tricks for IntelliJ IDEA","link":"./tips-and-tricks"},"files":[]},"headers":[],"relativePath":"1.21.8/develop/getting-started/intellij-idea/generating-sources.md","filePath":"versions/1.21.8/develop/getting-started/intellij-idea/generating-sources.md","lastUpdated":1760721669000}`);var u={name:`1.21.8/develop/getting-started/intellij-idea/generating-sources.md`};function d(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Generating Sources in IntelliJ IDEA <a class="header-anchor" href="#h1" aria-label="Permalink to “Generating Sources in IntelliJ IDEA”">​</a></h1><p>The Fabric toolchain lets you access the Minecraft source code by generating it locally, and you can use IntelliJ IDEA to conveniently navigate through it. To generate sources, you need to run the <code>genSources</code> Gradle task.</p><p>This can be done from the Gradle View like above, by running the <code>genSources</code> task in <strong>Tasks</strong> &gt; <strong><code>fabric</code></strong>: <img src="/assets/develop/getting-started/intellij/gradle-gensources.png" alt=" Task in Gradle Panel" loading="lazy"></p><p>Or you can also run the command from the terminal:</p><div class="language-sh"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./gradlew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> genSources</span></span></code></pre></div><p><img src="/assets/develop/getting-started/intellij/terminal-gensources.png" alt=" Task in Terminal" loading="lazy"></p><h2 id="attaching-sources" tabindex="-1">Attaching Sources <a class="header-anchor" href="#attaching-sources" aria-label="Permalink to “Attaching Sources”">​</a></h2><p>IntelliJ requires one additional step of attaching generated sources to the project.</p><p>To do this, open any Minecraft class. You can <kbd>Ctrl</kbd> + Click to go to the definition, which opens the class or use &quot;Search everywhere&quot; to open a class.</p><p>Lets open <code>MinecraftServer.class</code> as an example. You should now see a blue banner on the top with a &quot;<strong>Choose Sources...</strong>&quot; link.</p><p><img src="/assets/develop/getting-started/intellij/choose-sources.png" alt="Choose Sources" loading="lazy"></p><p>Click on &quot;<strong>Choose Sources...</strong>&quot; to open a file selector dialog. This dialog will open at the correct location of generated sources by default.</p><p>Select the file that ends with <strong><code>-sources</code></strong> and press <strong>Open</strong> to confirm the selection.</p><p><img src="/assets/develop/getting-started/intellij/choose-sources-dialog.png" alt="Choose Sources Dialog" loading="lazy"></p><p>If the correct file is open, you should now be able to see Javadoc comments as well as have the ability to search for references.</p><p><img src="/assets/develop/getting-started/intellij/javadoc.png" alt="Javadoc Comments in Sources" loading="lazy"></p>`,16)]])}var f=r(u,[[`render`,d]]);export{l as __pageData,f as default};